import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.gU7RhlGX.js";const u=JSON.parse('{"title":"AI 时代要如何取舍","description":"","frontmatter":{},"headers":[],"relativePath":"不可不知的Ai知识/AI时代要如何取舍.md","filePath":"不可不知的Ai知识/AI时代要如何取舍.md","lastUpdated":1776422487000}'),i={name:"不可不知的Ai知识/AI时代要如何取舍.md"};function n(l,e,s,h,d,g){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="ai-时代要如何取舍" tabindex="-1">AI 时代要如何取舍 <a class="header-anchor" href="#ai-时代要如何取舍" aria-label="Permalink to &quot;AI 时代要如何取舍&quot;">​</a></h1><p>AI 发展日新月异，概念、技术、产品层出不穷。在工作精力有限的情况下，盲目追逐浪潮会导致严重的焦虑与效率损耗。我们需要一套原则来辅助判断：<strong>哪些东西不必理会，哪些只需略知一二，而哪些值得深度投入。</strong></p><hr><h2 id="_1-核心判断标准-双维度准则" tabindex="-1">1. 核心判断标准：双维度准则 <a class="header-anchor" href="#_1-核心判断标准-双维度准则" aria-label="Permalink to &quot;1. 核心判断标准：双维度准则&quot;">​</a></h2><p>要判断一个 AI 新事物是否值得投入时间，只需自问两个核心维度：</p><h3 id="维度一-生产力距离-productivity-proximity" tabindex="-1">维度一：生产力距离 (Productivity Proximity) <a class="header-anchor" href="#维度一-生产力距离-productivity-proximity" aria-label="Permalink to &quot;维度一：生产力距离 (Productivity Proximity)&quot;">​</a></h3><blockquote><p><strong>“它离我现在的生产力有多近？”</strong></p></blockquote><p>关键不在于它离“AI 行业”多近，而在于离<strong>你的工作</strong>多近。</p><ul><li><strong>近</strong>：能直接减少重复劳动、提升产出质量。你能瞬间想到至少 2 个具体的使用场景。</li><li><strong>远</strong>：读完介绍后，依然想不出它具体能帮你解决什么当下的问题。</li></ul><h3 id="维度二-知识保鲜期-knowledge-shelf-life" tabindex="-1">维度二：知识保鲜期 (Knowledge Shelf Life) <a class="header-anchor" href="#维度二-知识保鲜期-knowledge-shelf-life" aria-label="Permalink to &quot;维度二：知识保鲜期 (Knowledge Shelf Life)&quot;">​</a></h3><blockquote><p><strong>“这个知识的价值能维持多久？”</strong></p></blockquote><p>有的知识能产生复利，有的则是纯粹的沉没成本。</p><ul><li><strong>长</strong>：今天学了，三年后依然有用（如系统思维、架构设计）。</li><li><strong>短</strong>：今天学了，三个月后可能连名字都换了（如某个特定的 API 或套壳产品的具体 UI 操作）。</li></ul><hr><h2 id="_2-投资矩阵-取舍策略" tabindex="-1">2. 投资矩阵：取舍策略 <a class="header-anchor" href="#_2-投资矩阵-取舍策略" aria-label="Permalink to &quot;2. 投资矩阵：取舍策略&quot;">​</a></h2><p>我们可以根据上述两个维度，将 AI 信息划分为不同的象限：</p><h3 id="🚫-低优先级-排除干扰" tabindex="-1">🚫 低优先级：排除干扰 <a class="header-anchor" href="#🚫-低优先级-排除干扰" aria-label="Permalink to &quot;🚫 低优先级：排除干扰&quot;">​</a></h3><blockquote><p>特征：离生产力远，且保鲜期短。</p></blockquote><p>这是噪音最密集的象限，也是最容易产生“虚假勤奋”的地方。</p><ul><li><strong>避坑列表</strong>： <ul><li>每月一变、甚至每周一变的模型跑分排名。</li><li>各种临时性的 AI 创业融资新闻。</li><li>各种 AI 套壳产品（绝大多数生存期超不过半年）。</li></ul></li></ul><h3 id="✅-高优先级-深度投入" tabindex="-1">✅ 高优先级：深度投入 <a class="header-anchor" href="#✅-高优先级-深度投入" aria-label="Permalink to &quot;✅ 高优先级：深度投入&quot;">​</a></h3><blockquote><p>特征：离生产力近，且保鲜期长。</p></blockquote><p>这里是真正值得投入时间研究、反复实践并建立深度认知的领域。</p><ul><li><strong>判断标准</strong>： <ol><li>你已在日常使用它，但感觉仅挖掘了不到 20% 的潜力。</li><li>背后有成熟的体系、平台或扎实的工程规律在持续支撑。</li></ol></li></ul><hr><h2 id="_3-开发者实战-如何投资你的精力" tabindex="-1">3. 开发者实战：如何投资你的精力 <a class="header-anchor" href="#_3-开发者实战-如何投资你的精力" aria-label="Permalink to &quot;3. 开发者实战：如何投资你的精力&quot;">​</a></h2><p>对于软件开发者来说，以下领域属于<strong>高优先级</strong>象限：</p><h3 id="软件工程根基-software-engineering-essentials" tabindex="-1">软件工程根基 (Software Engineering Essentials) <a class="header-anchor" href="#软件工程根基-software-engineering-essentials" aria-label="Permalink to &quot;软件工程根基 (Software Engineering Essentials)&quot;">​</a></h3><p>软件工程本身就是保鲜期最长的知识系统。设计模式、抽象能力、系统思维和代码质量，其价值以十年计。AI 时代反而更需要你具备强大的工程判断力，来决定 AI 生成的代码是否可用、架构是否合理。</p><h3 id="上下文工程-context-engineering" tabindex="-1">上下文工程 (Context Engineering) <a class="header-anchor" href="#上下文工程-context-engineering" aria-label="Permalink to &quot;上下文工程 (Context Engineering)&quot;">​</a></h3><p>这是系统设计能力在 AI 时代的延伸。其核心是管理 AI 执行任务时的整个信息环境（用户画像、对话历史、文档检索、工具链）。这是开发者已有的能力迁移，不需要从零开始，且保鲜期极长。</p><h3 id="平台级智能体-platform-agents" tabindex="-1">平台级智能体 (Platform Agents) <a class="header-anchor" href="#平台级智能体-platform-agents" aria-label="Permalink to &quot;平台级智能体 (Platform Agents)&quot;">​</a></h3><p>如 <strong>Claude Code</strong> 这类直接作用于核心工作流、且有大型平台（Anthropic）持续投入的产品。值得投入时间去摸透其能力边界，而非仅仅用于补全代码。</p><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><blockquote><p><strong>深度使用一个核心工具带来的复利效应，远大于浅尝辄止地体验十个工具。</strong></p></blockquote><p>在 AI 浪潮中保持定力的关键，在于将精力收缩到那些<strong>能直接转化为生产力</strong>且<strong>具有跨周期潜质</strong>的领域。</p>',37)])])}const p=a(i,[["render",n]]);export{u as __pageData,p as default};
